option.value:
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --gold-primary: #c8a24e;
  --gold-light: #f0deb0;
  --gold-dark: #8b6914;
  --cream: #fef9e7;
  --cream-dark: #f5e6b8;
  --royal-dark: #2d2312;
}

* {
  box-sizing: border-box;
}

body {
  font-family: 'Sarabun', 'Prompt', 'Noto Sans Thai', sans-serif;
  background: linear-gradient(180deg, #fffdf7 0%, #fef9e7 100%);
  color: #2d2312;
  min-height: 100vh;
}

/* ===== Ornamental Divider ===== */
.ornament-divider {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-top: 1rem;
  margin-bottom: 1rem;
  margin-left: auto;
  margin-right: auto;
}
.ornament-divider::before,
.ornament-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: linear-gradient(90deg, transparent, #c8a24e, transparent);
}
.ornament-divider .diamond {
  width: 8px;
  height: 8px;
  background: #c8a24e;
  transform: rotate(45deg);
  flex-shrink: 0;
}

/* ===== Gold Border Top on Cards ===== */
.card-royal {
  background: #ffffff;
  border: 1px solid rgba(200, 162, 78, 0.15);
  border-top: 3px solid #c8a24e;
  border-radius: 12px;
  padding: 1.5rem;
  box-shadow: 0 1px 8px rgba(0,0,0,0.04), 0 0 0 1px rgba(200,162,78,0.05);
  transition: box-shadow 0.3s ease, transform 0.3s ease;
}
.card-royal:hover {
  box-shadow: 0 8px 32px rgba(0,0,0,0.06), 0 2px 12px rgba(200,162,78,0.1);
}

.card-royal-flat {
  background: #ffffff;
  border: 1px solid rgba(200, 162, 78, 0.15);
  border-radius: 12px;
  padding: 1.5rem;
  box-shadow: 0 1px 8px rgba(0,0,0,0.03);
}

.card-glass {
  background: rgba(255,255,255,0.8);
  backdrop-filter: blur(12px);
  border: 1px solid rgba(200, 162, 78, 0.15);
  border-radius: 12px;
  padding: 1.5rem;
  box-shadow: 0 4px 24px rgba(0,0,0,0.04);
}

/* ===== Buttons ===== */
.btn-gold {
  background: linear-gradient(135deg, #daa520 0%, #c8a24e 50%, #b8860b 100%);
  color: #fff;
  font-weight: 600;
  padding: 0.65rem 1.5rem;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  transition: all 0.25s ease;
  box-shadow: 0 2px 8px rgba(200,162,78,0.25);
  text-decoration: none;
  display: inline-block;
}
.btn-gold:hover {
  box-shadow: 0 6px 24px rgba(200,162,78,0.4);
  filter: brightness(1.05);
  transform: translateY(-1px);
}
.btn-gold:active {
  transform: translateY(0);
}
.btn-gold:disabled {
  opacity: 0.6;
  cursor: not-allowed;
  transform: none;
}

.btn-outline-gold {
  background: transparent;
  color: #8b6914;
  font-weight: 600;
  padding: 0.6rem 1.5rem;
  border-radius: 10px;
  border: 2px solid #c8a24e;
  cursor: pointer;
  transition: all 0.25s ease;
  text-decoration: none;
  display: inline-block;
}
.btn-outline-gold:hover {
  background: linear-gradient(135deg, #daa520, #c8a24e);
  color: #fff;
  box-shadow: 0 4px 16px rgba(200,162,78,0.3);
  transform: translateY(-1px);
}

/* ===== Inputs — use @layer so Tailwind utilities (pl-10 etc.) can override ===== */
@layer components {
  .input-royal {
    width: 100%;
    padding: 0.7rem 1rem;
    border: 1.5px solid rgba(200, 162, 78, 0.25);
    border-radius: 10px;
    background: #fffdf7;
    color: #2d2312;
    font-family: inherit;
    font-size: 0.95rem;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
  }
  .input-royal:focus {
    outline: none;
    border-color: #c8a24e;
    box-shadow: 0 0 0 3px rgba(200, 162, 78, 0.12);
  }
  .input-royal::placeholder {
    color: #b49a64;
  }
}

/* ===== Section Title ===== */
.section-title {
  font-size: 1.15rem;
  font-weight: 700;
  color: #4a3a20;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}
.section-title::before {
  content: '';
  width: 3px;
  height: 1.1em;
  background: linear-gradient(180deg, #daa520, #b8860b);
  border-radius: 2px;
}

/* ===== Vote Result Bars ===== */
.vote-bar {
  height: 8px;
  border-radius: 4px;
  background: #ede8d8;
  overflow: hidden;
}
.vote-bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 0.6s ease;
}
.vote-bar-agree { background: linear-gradient(90deg, #22c55e, #16a34a); }
.vote-bar-disagree { background: linear-gradient(90deg, #ef4444, #dc2626); }
.vote-bar-abstain { background: linear-gradient(90deg, #eab308, #ca8a04); }

/* ===== Scrollbar ===== */
::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: #fef9e7; }
::-webkit-scrollbar-thumb { background: #c8a24e; border-radius: 3px; }

/* ===== Status badges ===== */
.badge-success {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 3px 12px;
  background: #dcfce7;
  color: #166534;
  border-radius: 999px;
  font-size: 0.8rem;
  font-weight: 600;
  border: 1px solid #bbf7d0;
}
.badge-danger {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 3px 12px;
  background: #fef2f2;
  color: #991b1b;
  border-radius: 999px;
  font-size: 0.8rem;
  font-weight: 600;
  border: 1px solid #fecaca;
}
.badge-gold {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 3px 12px;
  background: #fef9e7;
  color: #8b6914;
  border: 1px solid rgba(200,162,78,0.3);
  border-radius: 999px;
  font-size: 0.8rem;
  font-weight: 600;
}

/* ===== School logo avatar ===== */
.school-avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  border: 2px solid rgba(200,162,78,0.2);
  object-fit: contain;
  background: #fff;
  padding: 2px;
  flex-shrink: 0;
}
.school-avatar-sm {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  border: 1.5px solid rgba(200,162,78,0.2);
  object-fit: contain;
  background: #fff;
  padding: 1px;
  flex-shrink: 0;
}
.school-avatar-lg {
  width: 56px;
  height: 56px;
  border-radius: 50%;
  border: 2.5px solid rgba(200,162,78,0.25);
  object-fit: contain;
  background: #fff;
  padding: 3px;
  flex-shrink: 0;
  box-shadow: 0 2px 8px rgba(0,0,0,0.06);
}

/* ===== Hero gradient ===== */
.hero-gradient {
  background: radial-gradient(ellipse at 50% 0%, rgba(200,162,78,0.08) 0%, transparent 70%);
}

/* ===== Vote button glow ===== */
.vote-btn {
  transition: all 0.3s ease;
  border: none;
  cursor: pointer;
}
.vote-btn-agree {
  background: linear-gradient(135deg, #22c55e, #16a34a);
  box-shadow: 0 4px 20px rgba(34,197,94,0.3);
}
.vote-btn-agree:hover {
  box-shadow: 0 8px 32px rgba(34,197,94,0.4);
  transform: translateY(-2px);
}
.vote-btn-disagree {
  background: linear-gradient(135deg, #ef4444, #dc2626);
  box-shadow: 0 4px 20px rgba(239,68,68,0.3);
}
.vote-btn-disagree:hover {
  box-shadow: 0 8px 32px rgba(239,68,68,0.4);
  transform: translateY(-2px);
}
.vote-btn-abstain {
  background: linear-gradient(135deg, #eab308, #ca8a04);
  box-shadow: 0 4px 20px rgba(234,179,8,0.3);
}
.vote-btn-abstain:hover {
  box-shadow: 0 8px 32px rgba(234,179,8,0.4);
  transform: translateY(-2px);
}

/* ===== Print styles ===== */
@media print {
  body { background: #fff !important; }
  .no-print { display: none !important; }
  .card-royal { box-shadow: none; border: 1px solid #ccc; break-inside: avoid; }
}

/* ===== Animations ===== */
.animate-fade-in {
  animation: fadeIn 0.4s ease-out;
}
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-fade-in-up {
  animation: fadeInUp 0.5s ease-out;
}
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(16px); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-scale-in {
  animation: scaleIn 0.3s ease-out;
}
@keyframes scaleIn {
  from { opacity: 0; transform: scale(0.95); }
  to { opacity: 1; transform: scale(1); }
}

/* ===== Logo marquee ===== */
.logo-marquee-track {
  display: flex;
  gap: 2.5rem;
  animation: marquee 30s linear infinite;
}
.logo-marquee-track:hover {
  animation-play-state: paused;
}
@keyframes marquee {
  from { transform: translateX(0); }
  to { transform: translateX(-50%); }
}

/* ===== Countdown large ===== */
.countdown-display {
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.05em;
}

